if (page.url().includes(`/course/${foreignCourse.id}`)) {
  await expect(
    page.getByRole("heading", { name: /have access to this course/i }),
    "a no-role user kept on the course route must see the graceful access-denied card, not a crash"
  ).toBeVisible();
}

